+fn random_bytes(len: usize) -> Vec<u8> {
+    let mut out = Vec::with_capacity(len);
+    while out.len() < len {
+        let bytes = Uuid::new_v4().into_bytes();
+        let remaining = len - out.len();
+        out.extend_from_slice(&bytes[..remaining.min(bytes.len())]);
+    }
+    out
+}
